// Flatten the hierarchy into a list of procedures with breadcrumb metadata —
// useful for everything that operates on a procedure (Note Builder, Prep List,
// jump handlers).
function getAllProcedures() {
 const out = [];
 for (const cat of CATEGORIES) {
 for (const grp of cat.groups) {
 for (const proc of grp.procedures) {
 out.push({
 id: proc.id,
 label: proc.label,
 categoryId: cat.id,
 categoryLabel: cat.label,
 groupId: grp.id,
 groupLabel: grp.label,
 breadcrumb: `${cat.label} → ${grp.label} → ${proc.label}`,
...(proc.pinnedCodes && { pinnedCodes: proc.pinnedCodes }),
 });
 }
 }
 }
 return out;
}

const ALL_PROCEDURES = getAllProcedures();
const findProcedure = (id) => ALL_PROCEDURES.find(p => p.id === id);

// Flatten a category's groups into a single procedures list with each
// procedure tagged with its group label as a prefix where helpful. This
// preserves the simpler 2-dropdown picker used by Note Builder and Prep
// List while still giving users the group context they'd see in Browse.
function flattenCategory(cat) {
 const procs = [];
 for (const grp of cat.groups) {
 for (const p of grp.procedures) {
 // If a category has only one group OR the group label is generic
 // ("Procedures"), don't prefix it (would be noise).
 const showPrefix =
 cat.groups.length > 1 &&
 grp.procedures.length > 1 &&
 grp.label!== "Procedures";
 const label = showPrefix? `${grp.label} — ${p.label}`: p.label;
 procs.push({ id: p.id, label, groupId: grp.id, groupLabel: grp.label });
 }
 }
 return {...cat, procedures: procs };
}

// All categories with.procedures available (for NoteBuilder).
// Exclude misc (Axium workflows / lookup references — no note codes) and
// lab (lab Rx text goes to Axium's Labs > Details field, not the chart note).
const FLAT_CATEGORIES = CATEGORIES.filter(c => c.id!== "misc" && c.id!== "lab").map(flattenCategory);

// Browse tab: every category. Lab Scripts used to be filtered out because the
// per-procedure pages had no CHUNKS content; each lab Rx now has a REF_DATA
// entry with the Rx body + supplements + Swade turnaround, so they belong
// here too.
const BROWSE_CATEGORIES = CATEGORIES;

/* ============================================================================
 * REF_DATA — structured rendering for Misc. > Lookup procedures.
 *
 * Lookup chunks are reference material (BP categories, drug catalog, materials,
 * prescription formulations, caries staging). The raw bodies are space-aligned
 * ASCII tables that render badly in any proportional font. Rather than force
 * monospace, we hand-author structured data here and render it with proper
 * typography. Procedures NOT keyed in this map fall back to ProseBlock — fine
 * for the prose-heavy ones (anesthesia narrative, MRONJ, pregnant pts, etc.).
 *
 * Block shapes:
 * { type: "table", caption?, headers, rows, footnote? }
 * { type: "cards", caption?, cards: [{ title, subtitle?, body?, rows? }] }
 * { type: "prose", heading?, lines: [...] }
 * ==========================================================================*/
